export default class CreateConnectionHandler {
  static $inject: string[];

  /**
   * @param canvas
   * @param layouter
   */
  constructor(canvas: Canvas, layouter: Layouter);

  /**
   * Creates a new connection between two elements.
   *
   * @param context
   * connection to the parent's children.
   */
  execute(context: {
      source: Element;
      target: Element;
      parent: Shape;
      parentIndex?: number;
      hints?: ModelingHints;
  }): any;

  revert(context: any): any;
}

type Element = import("../../../model/Types.js").Element;
type Shape = import("../../../model/Types.js").Shape;
type Point = import("../../../util/Types.js").Point;
type ModelingHints = import("../Modeling.js").ModelingHints;
type Canvas = import("../../../core/Canvas.js").default;
type Layouter = import("../../../layout/BaseLayouter.js").default;